:root { --accent: #53f4ff; --bg: #090b18; }
* { box-sizing: border-box; }
body { margin: 0; min-height: 100vh; display: grid; place-items: center; font-family: system-ui; color: white; background: radial-gradient(circle at top, #26366b, var(--bg)); }
#app { width: min(620px, 90vw); padding: 48px; text-align: center; border: 1px solid #ffffff33; border-radius: 28px; background: #ffffff12; }
button { padding: 12px 18px; border: 0; border-radius: 999px; background: var(--accent); font-weight: 800; cursor: pointer; }

const button = document.querySelector('#demoButton');
button?.addEventListener('click', () => {
  button.textContent = 'FileVerse launched ✓';
});
